-- STRUCTURE
DROP TABLE IF EXISTS sites; 
DROP TABLE IF EXISTS engins; 
DROP TABLE IF EXISTS production; 
DROP TABLE IF EXISTS exportations;

-- 1. Création des tables
CREATE TABLE sites (
    id_site INTEGER PRIMARY KEY, 
    nom TEXT, 
    province TEXT
);

CREATE TABLE engins (
    id_engin INTEGER PRIMARY KEY, 
    type TEXT, 
    id_site INTEGER, 
    FOREIGN KEY(id_site) REFERENCES sites(id_site)
);

CREATE TABLE production (
    id_prod INTEGER PRIMARY KEY, 
    date_prod DATE, 
    id_site INTEGER, 
    type_minerai TEXT, 
    tonnage_brut REAL, 
    teneur REAL, 
    FOREIGN KEY(id_site) REFERENCES sites(id_site)
);

CREATE TABLE exportations (
    id_export INTEGER PRIMARY KEY, 
    date_export DATE, 
    id_site INTEGER, 
    tonnage_vendu REAL, 
    prix_unitaire_usd REAL, 
    FOREIGN KEY(id_site) REFERENCES sites(id_site)
);

